var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"LUDWIG_MOONLIGHT_NPC_NULL","text":{"KOREA":"먼 길까지 고생이 많았네. 자네가 발렌티누스 수도원에서 파견된 수녀인가?","JPN":"遠路はるばるご苦労だった。君がバレンチヌス修道院から派遣されたシスターかね？","ENG":"You've come a long way. You must be the nun sent from the Valentinus Monastery.","TWN":"一路上辛苦了。你是聖華倫修道院派來的修女嗎？"},"stage":{"bg":"RESTAURANT_01","slots":{"L":null,"C":{"char_id":"LUDWIG_MOONLIGHT_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"네. 루시아 릿지라고 합니다.","JPN":"はい。ルシア・リッジです。","ENG":"Yes. My name is Lucia Ridge.","TWN":"是的，我叫露西卡·李奇。"},"stage":{"bg":"RESTAURANT_01","slots":{"L":null,"C":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"LUDWIG_MOONLIGHT_NPC_NULL","text":{"KOREA":"표정이 많이 좋지 않군. 혹시 뭔가 불편한 점이 있다면…….","JPN":"浮かない顔だな。もし何か気に入らないことがあるなら……","ENG":"You look upset. Is something bothering you?","TWN":"你的表情看起來不太好。如果有什麼不舒服的地方……"},"stage":{"bg":"RESTAURANT_01","slots":{"L":{"char_id":"LUDWIG_MOONLIGHT_NPC_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L9_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"아하하. 그럴 리가요.","JPN":"あはは、そんな。","ENG":"Ahaha, of course not.","TWN":"哈哈，怎麼可能。"},"stage":{"bg":"RESTAURANT_01","slots":{"L":{"char_id":"LUDWIG_MOONLIGHT_NPC_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L10_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"생각해 보면, 푯값도 이 아저씨가 다 내줬어야 하는 거 아냐?","JPN":"考えてみたら交通費もこのおっさんが全部出すべきだろ？","ENG":"Now that I think about it, shouldn't this guy have covered my travel expenses too?","TWN":"仔細想想，這個大叔應該幫我付咖啡錢吧？"},"stage":{"bg":"RESTAURANT_01","slots":{"L":{"char_id":"LUDWIG_MOONLIGHT_NPC_NULL","face":"UNIT_SERIOUS"},"C":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"게다가 이 다 무너져가는 카페는 뭐냐고!","JPN":"それに、このボロボロのカフェはなんだよ！","ENG":"And what is up with this run-down cafe?!","TWN":"而且這家快要倒閉的咖啡廳是怎麼回事啊！"},"stage":{"bg":"RESTAURANT_01","slots":{"L":{"char_id":"LUDWIG_MOONLIGHT_NPC_NULL","face":"UNIT_SERIOUS"},"C":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"이건 전형적인 돈 안 내고 뻐기다가 잠수타는 패턴이잖아!","JPN":"こいつは金を払わずにゴネて、行方をくらます典型的なパターンじゃねえか！","ENG":"This is exactly how people ghost you after dodging a payment!","TWN":"這不就是典型的詐騙手法嗎？先假裝有錢，等你上鉤後再捲款潛逃！"},"stage":{"bg":"RESTAURANT_01","slots":{"L":{"char_id":"LUDWIG_MOONLIGHT_NPC_NULL","face":"UNIT_SERIOUS"},"C":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"저택까지 있는 대부호라더니, 사실 다 압류 상태인 거 아냐?","JPN":"邸宅まで持ってる大富豪って言ってるけど、実は全部差し押さえられてるとか？","ENG":"A noble with a mansion, huh? What if all his assets have already been seized?","TWN":"說是擁有豪宅的大富翁，其實所有財產都被查封了吧？"},"stage":{"bg":"RESTAURANT_01","slots":{"L":{"char_id":"LUDWIG_MOONLIGHT_NPC_NULL","face":"UNIT_SERIOUS"},"C":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"루드윅 형제님의 고통을 하루라도 빨리 해결하지 못해 아픈 마음이 얼굴에 드러난 모양입니다.","JPN":"ブラザー・ルードヴィヒの苦痛を一日でも早く解決したいのに、そうできない苦しみが顔に出たようです。","ENG":"It seems my sorrow for not being able to ease your suffering sooner is showing on my face.","TWN":"想到沒能儘快解決你的痛苦，我的心甚是難過啊。"},"stage":{"bg":"RESTAURANT_01","slots":{"L":{"char_id":"LUDWIG_MOONLIGHT_NPC_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L16_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"오늘은 신께 고해성사를 올려야겠군요.","JPN":"今日は神に告解しなければなりませんね。","ENG":"I'll have to confess my sins today.","TWN":"今天得向主認真的懺悔了。"},"stage":{"bg":"RESTAURANT_01","slots":{"L":{"char_id":"LUDWIG_MOONLIGHT_NPC_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"일찍이 형제님의 고통을 헤아리지 못한 죄를 저질렀으니까.","JPN":"早くにブラザーの苦痛に気づけなかったという罪を犯したのですから。","ENG":"After all, it would be wrong not to repent for failing to see your pain earlier.","TWN":"因為我曾經犯下了未能體諒你痛苦的罪過。"},"stage":{"bg":"RESTAURANT_01","slots":{"L":{"char_id":"LUDWIG_MOONLIGHT_NPC_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L18_1","type":"dialog","speaker":"LUDWIG_MOONLIGHT_NPC_NULL","text":{"KOREA":"뭘 그렇게까지.","JPN":"何もそこまで。","ENG":"That's a bit much.","TWN":"是也沒必要這樣。"},"stage":{"bg":"RESTAURANT_01","slots":{"L":{"char_id":"LUDWIG_MOONLIGHT_NPC_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L19_1","type":"dialog","speaker":"LUDWIG_MOONLIGHT_NPC_NULL","text":{"KOREA":"그간 별장에서 지내고 있었으니, 이곳 사정을 몰랐던 것뿐이네.","JPN":"今まで別荘で暮らしていたせいで、ここの事情に詳しくなかっただけだ。","ENG":"I've been staying at my villa, so I wasn't aware of the situation in town.","TWN":"因為一直住在別墅，所以不知道這裡的情況。"},"stage":{"bg":"RESTAURANT_01","slots":{"L":{"char_id":"LUDWIG_MOONLIGHT_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L21_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"별장……? 실례지만 집을 몇 채씩 갖고 계신 건가요?","JPN":"別荘……？　失礼ですが、家を何軒所有していらっしゃるのですか？","ENG":"A villa...? Pardon me, but just how many houses do you own?","TWN":"別墅……？不好意思，你有幾套房子啊？"},"stage":{"bg":"RESTAURANT_01","slots":{"L":null,"C":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"LUDWIG_MOONLIGHT_NPC_NULL","text":{"KOREA":"집은 재무관리사를 통해 관리하고 있어서 잘 모르겠군.","JPN":"家は財務管理士を通じて管理しているから、よくわからないな。","ENG":"I wouldn't know. My financial manager handles all of them.","TWN":"房子是會計師在管理的，所以我不太清楚。"},"stage":{"bg":"RESTAURANT_01","slots":{"L":null,"C":{"char_id":"LUDWIG_MOONLIGHT_NPC_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"LUDWIG_MOONLIGHT_NPC_NULL","text":{"KOREA":"지금이라도 물어보면 되겠나?","JPN":"今からでも聞いてみた方がいいのかね？","ENG":"I can ask if you'd like?","TWN":"現在問還來得及嗎？"},"stage":{"bg":"RESTAURANT_01","slots":{"L":null,"C":{"char_id":"LUDWIG_MOONLIGHT_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"아뇨. 딱 제가 원하는 대답이었습니다. 형제님.","JPN":"いいえ。私が望んでいた答えでした、ブラザー。","ENG":"No need. That was exactly the answer I wanted to hear, brother.","TWN":"不，這正是我想要的回答。"},"stage":{"bg":"RESTAURANT_01","slots":{"L":null,"C":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"LUDWIG_MOONLIGHT_NPC_NULL","text":{"KOREA":"본론부터 이야기하지.","JPN":"本題から話そう。","ENG":"Let's get to the point.","TWN":"直接說重點吧。"},"stage":{"bg":"RESTAURANT_01","slots":{"L":null,"C":{"char_id":"LUDWIG_MOONLIGHT_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"LUDWIG_MOONLIGHT_NPC_NULL","text":{"KOREA":"지하 묘지에서 선조들이 일어나 영지를 망가뜨리고 있네.","JPN":"地下の墓地で先祖たちが起き上がり、領地を荒らしている。","ENG":"Ancestors have risen from the underground cemetery and are wreaking havoc on my lands.","TWN":"地下墓地裡的祖先復活了，他們正在破壞領地。"},"stage":{"bg":"RESTAURANT_01","slots":{"L":null,"C":{"char_id":"LUDWIG_MOONLIGHT_NPC_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"선조들이 일어났다…… 아주 흥미로운 심령 현상이네요.","JPN":"先祖たちが起き上がったと……とても興味深い心霊現象ですね。","ENG":"Ancestors rising from the dead... now that's an interesting ghost story.","TWN":"祖先甦醒了……真是有趣的靈異現象啊。"},"stage":{"bg":"RESTAURANT_01","slots":{"L":null,"C":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"LUDWIG_MOONLIGHT_NPC_NULL","text":{"KOREA":"나도 저택 관리인에게 들은 내용이네.","JPN":"私も邸宅の管理人から聞いた話だ。","ENG":"That's what my estate caretaker reported.","TWN":"我也是從管家那裡聽說的。"},"stage":{"bg":"RESTAURANT_01","slots":{"L":null,"C":{"char_id":"LUDWIG_MOONLIGHT_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"LUDWIG_MOONLIGHT_NPC_NULL","text":{"KOREA":"밤만 되면 정체불명의 소리가 들려 지하로 가니 선조들이 나타났다더군.","JPN":"夜になると正体不明の音が聞こえて地下に行ったところ、先祖たちが現れたそうだ。","ENG":"Apparently, every night, strange noises echo from below, and when they go to check, they see the ancestors there.","TWN":"一到晚上就會聽到莫名的聲音，到了地下看到祖先出現在眼前。"},"stage":{"bg":"RESTAURANT_01","slots":{"L":null,"C":{"char_id":"LUDWIG_MOONLIGHT_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"LUDWIG_MOONLIGHT_NPC_NULL","text":{"KOREA":"일로 인한 스트레스로 생각해 휴가를 보냈네만, 영 찝찝해서 말이지.","JPN":"仕事によるストレスだと思い休暇を出してやったのだが、どうも気になってね。","ENG":"I figured it was just work-related stress and gave them time off, but something about it still doesn't sit right with me.","TWN":"雖然我正在休假，但總覺得心裡怪怪的。"},"stage":{"bg":"RESTAURANT_01","slots":{"L":null,"C":{"char_id":"LUDWIG_MOONLIGHT_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"……후, 후후.","JPN":"……ふ、ふふ。","ENG":"...Ha, haha...","TWN":"……呵，呵呵。"},"stage":{"bg":"RESTAURANT_01","slots":{"L":null,"C":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"정말 잘 찾아오셨습니다. 루드윅 형제님.","JPN":"本当によく依頼してくださいました、ブラザー・ルードヴィヒ。","ENG":"Brother Ludwig, you've come to the right place.","TWN":"那你真是找對人了，路易弟兄。"},"stage":{"bg":"RESTAURANT_01","slots":{"L":null,"C":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};